#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c<=(b);++c)
using namespace std;
const int N=1e6+5;const long long INF=4e18;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res; 
}
int x[N],a[N],deq[N],h=1,t;long long dp[N],c[N],s[N];double K[N];
inline double Cnt(int a,int b){return 1.0*(dp[a]+s[a]*x[a]-c[a]-dp[b]-s[b]*x[b]+c[b])/(s[a]-s[b]);}
int main()
{
	int n=read();rep(1,n,i)x[i]=read(),s[i]=s[i-1]+read(),a[i]=read(); 
	rep(1,n,i)c[i]=c[i-1]+s[i-1]*(x[i]-x[i-1]);
	K[0]=-INF;deq[++t]=0;rep(1,n,i)
	{
		while(h<t&&Cnt(deq[h],deq[h+1])<x[i])h++;
		dp[i]=dp[deq[h]]+a[i]+c[i]-s[deq[h]]*(x[i]-x[deq[h]])-c[deq[h]];
		while(h<t&&Cnt(deq[t],deq[t-1])>Cnt(deq[t],i))t--;deq[++t]=i;
	}
	
//	rep(1,n,i)printf("%d ",dp[i]);
//	rep(1,n,i)rep(0,i-1,j)
//	{
//		dp[i]=min(dp[i],dp[j]+a[i]+c[i]-s[j]*(x[i]-x[j])-c[j]);
//	}
	printf("%lld\n",dp[n]);
}
